if (!defined('ABSPATH')) {
    exit;
}

class UFU_User_File_Uploads {
    private $upload_subdir = 'user-files';

    public function __construct() {
        add_shortcode('user_file_upload_form', array($this, 'render_form'));
        add_action('init', array($this, 'handle_upload'));
        add_action('wp_enqueue_scripts', array($this, 'enqueue_assets'));
    }

    public function enqueue_assets() {
        if (!is_user_logged_in()) {
            return;
        }
        wp_register_style('ufu-user-files', false);
        wp_enqueue_style('ufu-user-files');
        wp_add_inline_style('ufu-user-files', '
            .ufu-upload-form{max-width:600px;padding:20px;border:1px solid #ddd;background:#fff}
            .ufu-upload-form label{display:block;margin:0 0 8px;font-weight:600}
            .ufu-upload-form input[type="text"],
            .ufu-upload-form input[type="file"]{width:100%;margin:0 0 15px}
            .ufu-upload-form button{padding:10px 16px;cursor:pointer}
            .ufu-message{margin:15px 0;padding:10px 12px;border-radius:4px}
            .ufu-success{background:#e7f7ea;border:1px solid #b7e1c1}
            .ufu-error{background:#fde8e8;border:1px solid #f5b5b5}
        ');
    }

    public function render_form() {
        if (!is_user_logged_in()) {
            return '<p>You must be logged in to upload files.</p>';
        }

        $message = '';
        if (isset($_GET['ufu_upload']) && $_GET['ufu_upload'] === 'success') {
            $message = '<div class="ufu-message ufu-success">File uploaded successfully.</div>';
        } elseif (isset($_GET['ufu_upload']) && $_GET['ufu_upload'] === 'error') {
            $message = '<div class="ufu-message ufu-error">There was an error uploading your file.</div>';
        }

        ob_start();
        echo $message;
        ?>
        <form class="ufu-upload-form" method="post" enctype="multipart/form-data">
            <?php wp_nonce_field('ufu_upload_file_action', 'ufu_upload_file_nonce'); ?>
            <label for="ufu_file_label">File Label</label>
            <input type="text" name="ufu_file_label" id="ufu_file_label" placeholder="Profile Picture, ID Document, etc." required>

            <label for="ufu_user_file">Choose File</label>
            <input type="file" name="ufu_user_file" id="ufu_user_file" accept=".jpg,.jpeg,.png,.gif,.pdf,.doc,.docx,.txt,.xls,.xlsx,.ppt,.pptx" required>

            <button type="submit" name="ufu_upload_submit" value="1">Upload File</button>
        </form>
        <?php
        return ob_get_clean();
    }

    public function handle_upload() {
        if (!isset($_POST['ufu_upload_submit'])) {
            return;
        }

        if (!is_user_logged_in()) {
            wp_die('You must be logged in to upload files.');
        }

        if (
            !isset($_POST['ufu_upload_file_nonce']) ||
            !wp_verify_nonce($_POST['ufu_upload_file_nonce'], 'ufu_upload_file_action')
        ) {
            wp_die('Security check failed.');
        }

        if (!isset($_FILES['ufu_user_file']) || empty($_FILES['ufu_user_file']['name'])) {
            $this->redirect_with_status('error');
        }

        $file = $_FILES['ufu_user_file'];

        if (!empty($file['error']) && $file['error'] !== UPLOAD_ERR_OK) {
            $this->redirect_with_status('error');
        }

        $allowed_mimes = array(
            'jpg|jpeg|jpe' => 'image/jpeg',
            'png'          => 'image/png',
            'gif'          => 'image/gif',
            'pdf'          => 'application/pdf',
            'doc'          => 'application/msword',
            'docx'         => 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
            'txt'          => 'text/plain',
            'xls'          => 'application/vnd.ms-excel',
            'xlsx'         => 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
            'ppt'          => 'application/vnd.ms-powerpoint',
            'pptx'         => 'application/vnd.openxmlformats-officedocument.presentationml.presentation',
        );

        $overrides = array(
            'test_form' => false,
            'mimes'     => $allowed_mimes,
        );

        require_once ABSPATH . 'wp-admin/includes/file.php';
        require_once ABSPATH . 'wp-admin/includes/image.php';

        $uploaded = wp_handle_upload($file, $overrides);

        if (isset($uploaded['error'])) {
            $this->redirect_with_status('error');
        }

        $upload_dir = wp_upload_dir();
        $target_dir = trailingslashit($upload_dir['basedir']) . $this->upload_subdir;

        if (!file_exists($target_dir)) {
            wp_mkdir_p($target_dir);
        }

        $filename = wp_unique_filename($target_dir, basename($uploaded['file']));
        $new_file_path = trailingslashit($target_dir) . $filename;

        if (!@rename($uploaded['file'], $new_file_path)) {
            @copy($uploaded['file'], $new_file_path);
            @unlink($uploaded['file']);
        }

        if (!file_exists($new_file_path)) {
            $this->redirect_with_status('error');
        }

        $file_url = trailingslashit($upload_dir['baseurl']) . $this->upload_subdir . '/' . $filename;
        $user_id = get_current_user_id();
        $label = isset($_POST['ufu_file_label']) ? sanitize_text_field(wp_unslash($_POST['ufu_file_label'])) : '';
        $meta = array(
            'user_id'    => $user_id,
            'label'      => $label,
            'file_url'   => esc_url_raw($file_url),
            'file_path'  => $new_file_path,
            'file_name'  => sanitize_file_name($filename),
            'uploaded'   => current_time('mysql'),
        );

        $existing = get_user_meta($user_id, '_ufu_user_files', true);
        if (!is_array($existing)) {
            $existing = array();
        }
        $existing[] = $meta;
        update_user_meta($user_id, '_ufu_user_files', $existing);

        $this->redirect_with_status('success');
    }

    private function redirect_with_status($status) {
        $redirect = wp_get_referer();
        if (!$redirect) {
            $redirect = home_url('/');
        }
        $redirect = remove_query_arg(array('ufu_upload'), $redirect);
        $redirect = add_query_arg('ufu_upload', $status, $redirect);
        wp_safe_redirect($redirect);
        exit;
    }
}

new UFU_User_File_Uploads();